#!/bin/bash
# Tencent Cloud Web Terminal Deploy - V8 Fix

echo "============================================"
echo "  Artist Manager V8 - Web Deploy"
echo "============================================"
echo ""
sudo mkdir -p /app/server /app/src /app/data
echo "[1/3] Writing files..."

echo "  /app/server.js"
base64 -d <<'SERVEREOF' | sudo tee /app/server.js > /dev/null

SERVEREOF

echo "  /app/server/database.js"
base64 -d <<'DBEOF' | sudo tee /app/server/database.js > /dev/null

DBEOF

echo "  /app/package.json"
base64 -d <<'PKGEOF' | sudo tee /app/package.json > /dev/null

PKGEOF

echo "  /app/src/index.html"
base64 -d <<'HTMLEOF' | sudo tee /app/src/index.html > /dev/null

HTMLEOF

echo ""
echo "[2/3] Installing dependencies..."
cd /app && npm install --registry=https://registry.npmmirror.com 2>&1 | tail -5
echo ""
echo "[3/3] Restarting server..."
sudo pkill -f "node /app/server.js" 2>/dev/null
sleep 1
sudo nohup env PORT=8080 DB_PATH=/app/data/artist_data.db node /app/server.js > /app/server.log 2>&1 &
sleep 3
echo ""
echo "Verifying..."
curl -s http://localhost:8080/api/ping
echo ""
curl -s http://localhost:8080/api/health
echo ""
echo "============================================"
echo "  Deploy complete!"
echo "  http://42.194.230.53:8080"
echo "============================================"
